sys_script.script:
/**
 * Business Rule: After consumption with user_rating is updated
 * - Recalculates average_rating on the beer_model
 */
(function consumptionRatingUpdate(current, previous) {
    var beerModelId = current.getValue('beer_model');

    var aggregate = new GlideAggregate('x_1838075_pub_cr_0_consumption');
    aggregate.addQuery('beer_model', beerModelId);
    aggregate.addNotNullQuery('user_rating');
    aggregate.addAggregate('AVG', 'user_rating');
    aggregate.query();

    var avgRating = 0;
    if (aggregate.next()) {
        avgRating = parseFloat(aggregate.getAggregate('AVG', 'user_rating')) || 0;
    }

    var beerModel = new GlideRecord('x_1838075_pub_cr_0_beer_model');
    if (beerModel.get(beerModelId)) {
        beerModel.setValue('average_rating', avgRating);
        beerModel.update();
    }
})(current, previous);
